class Solution:
    def titleToNumber(self, s: str) -> int:
        res = 0
        for c in s:
            res = res * 26 + (ord(c) - ord('A') + 1)
        return res

solutions.cpp:
class Solution {
public:
    int titleToNumber(string s) {
        long long res = 0;
        for (char c : s) res = res * 26 + (c - 'A' + 1);
        return (int)res;
    }
};

